"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

const stepperVariants = cva("flex gap-4", {
  variants: {
    orientation: {
      horizontal: "flex-row items-center",
      vertical: "flex-col",
    },
  },
  defaultVariants: {
    orientation: "horizontal",
  },
})

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(stepperVariants({ orientation }), className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn("group/stepper-item flex items-center gap-3", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

const stepperTriggerVariants = cva(
  "inline-flex size-9 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      state: {
        completed: "border-primary bg-primary text-primary-foreground",
        active: "border-primary bg-background text-primary",
        pending:
          "border-muted-foreground/30 bg-background text-muted-foreground",
      },
    },
    defaultVariants: {
      state: "pending",
    },
  }
)

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(stepperTriggerVariants({ state }), className)}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-state={state === "completed" ? "completed" : "pending"}
      className={cn(
        "transition-colors",
        orientation === "horizontal"
          ? "h-0.5 min-w-4 flex-1"
          : "ml-4.5 h-6 w-0.5",
        state === "completed"
          ? "bg-primary"
          : "bg-muted-foreground/30",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

